14:     internal static class BestTypeInferrer
15:     {
16:         public static NullableAnnotation GetNullableAnnotation(ArrayBuilder<TypeWithAnnotations> types)
17:         {
18: #if DEBUG
19:             var example = types.FirstOrDefault(t => t.HasType);
20: #endif
21: 
22:             var result = NullableAnnotation.NotAnnotated;
23:             foreach (var type in types)
24:             {
25: #if DEBUG
26:                 Debug.Assert(!type.HasType || type.Equals(example, TypeCompareKind.AllIgnoreOptions));
27: #endif
28: 
29:                 // This uses the covariant merging rules.
30:                 result = result.Join(type.NullableAnnotation);
31:             }
32: 
33:             return result;
34:         }
