36:         public static NullableFlowState GetNullableState(ArrayBuilder<TypeWithState> types)
37:         {
38:             NullableFlowState result = NullableFlowState.NotNull;
39:             foreach (var type in types)
40:             {
41:                 result = result.Join(type.State);
42:             }
43: 
44:             return result;
45:         }
