112:         /// <remarks>
113:         /// This method implements best type inference for the conditional operator ?:.
114:         /// NOTE: If either expression is an error type, we return error type as the inference result.
115:         /// </remarks>
116:         public static TypeSymbol? InferBestTypeForConditionalOperator(
117:             BoundExpression expr1,
118:             BoundExpression expr2,
119:             Conversions conversions,
120:             out bool hadMultipleCandidates,
121:             ref CompoundUseSiteInfo<AssemblySymbol> useSiteInfo)
122:         {
123:             // SPEC:    The second and third operands, x and y, of the ?: operator control the type of the conditional expression. 
124:             // SPEC:    •	If x has type X and y has type Y then
125:             // SPEC:        o	If an implicit conversion (§6.1) exists from X to Y, but not from Y to X, then Y is the type of the conditional expression.
126:             // SPEC:        o	If an implicit conversion (§6.1) exists from Y to X, but not from X to Y, then X is the type of the conditional expression.
127:             // SPEC:        o	Otherwise, no expression type can be determined, and a compile-time error occurs.
128:             // SPEC:    •	If only one of x and y has a type, and both x and y, are implicitly convertible to that type, then that is the type of the conditional expression.
129:             // SPEC:    •	Otherwise, no expression type can be determined, and a compile-time error occurs.
130: 
131:             // A type is a candidate if all expressions are convertible to that type.
132:             ArrayBuilder<TypeSymbol> candidateTypes = ArrayBuilder<TypeSymbol>.GetInstance();
133:             try
134:             {
135:                 var conversionsWithoutNullability = conversions.WithNullability(false);
136: 
137:                 Debug.Assert(!NullableWalker.IsTargetTypedExpression(expr1));
138:                 if (expr1.Type is { } type1)
139:                 {
140:                     if (type1.IsErrorType())
141:                     {
142:                         hadMultipleCandidates = false;
143:                         return type1;
144:                     }
145: 
146:                     if (conversionsWithoutNullability.ClassifyImplicitConversionFromExpression(expr2, type1, ref useSiteInfo).Exists)
147:                     {
148:                         candidateTypes.Add(type1);
149:                     }
150:                 }
151: 
152:                 Debug.Assert(!NullableWalker.IsTargetTypedExpression(expr2));
153:                 if (expr2.Type is { } type2)
154:                 {
155:                     if (type2.IsErrorType())
156:                     {
157:                         hadMultipleCandidates = false;
158:                         return type2;
159:                     }
160: 
161:                     if (conversionsWithoutNullability.ClassifyImplicitConversionFromExpression(expr1, type2, ref useSiteInfo).Exists)
162:                     {
163:                         candidateTypes.Add(type2);
164:                     }
165:                 }
166: 
167:                 hadMultipleCandidates = candidateTypes.Count > 1;
168: 
169:                 return GetBestType(candidateTypes, conversions, ref useSiteInfo);
170:             }
171:             finally
172:             {
173:                 candidateTypes.Free();
174:             }
175:         }
