177:         internal static TypeSymbol? GetBestType(
178:             ArrayBuilder<TypeSymbol> types,
179:             ConversionsBase conversions,
180:             ref CompoundUseSiteInfo<AssemblySymbol> useSiteInfo)
181:         {
182:             // This code assumes that the types in the list are unique. 
183: 
184:             // This code answers the famous Mike Montwill interview question: Can you find the 
185:             // unique best member of a set in O(n) time if the pairwise betterness algorithm 
186:             // might be intransitive?
187: 
188:             // Short-circuit some common cases.
189:             switch (types.Count)
190:             {
191:                 case 0:
192:                     return null;
193:                 case 1:
194:                     return checkType(types[0]);
195:             }
196: 
197:             TypeSymbol? best = null;
198:             int bestIndex = -1;
199:             for (int i = 0; i < types.Count; i++)
200:             {
201:                 TypeSymbol? type = checkType(types[i]);
202:                 if (type is null)
203:                 {
204:                     continue;
205:                 }
206:                 if (best is null)
207:                 {
208:                     best = type;
209:                     bestIndex = i;
210:                 }
211:                 else
212:                 {
213:                     var better = Better(best, type, conversions, ref useSiteInfo);
214: 
215:                     if (better is null)
216:                     {
217:                         best = null;
218:                     }
219:                     else
220:                     {
221:                         best = better;
222:                         bestIndex = i;
223:                     }
224:                 }
225:             }
226: 
227:             if (best is null)
228:             {
229:                 return null;
230:             }
231: 
232:             // We have actually only determined that every type *after* best was worse. Now check
233:             // that every type *before* best was also worse.
234:             for (int i = 0; i < bestIndex; i++)
235:             {
236:                 TypeSymbol? type = checkType(types[i]);
237:                 if (type is null)
238:                 {
239:                     continue;
240:                 }
241:                 TypeSymbol? better = Better(best, type, conversions, ref useSiteInfo);
242:                 if (!best.Equals(better, TypeCompareKind.IgnoreNullableModifiersForReferenceTypes))
243:                 {
244:                     return null;
245:                 }
246:             }
247: 
248:             return best;
